namespace sv_879ae826edc24b989e8f493005b62180.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse.
/// Scoped lifetime ensures each circuit (each user session) gets its own instance.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
        ("WH-D", "Warehouse D"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _currentWarehouseId).Name
        ?? _currentWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_879ae826edc24b989e8f493005b62180.Services;

/// <summary>
/// Scoped service that provides low-stock alert counts and notifies all
/// subscribed components when new data arrives. Each circuit gets its own
/// instance, so different users see independent alert counts.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int CurrentAlertCount { get; private set; }

    /// <summary>
    /// Fired from a background thread whenever new alert data is fetched.
    /// Subscribers MUST wrap StateHasChanged in InvokeAsync.
    /// </summary>
    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += OnWarehouseChanged;
    }

    /// <summary>Simulates a database query returning a random low-stock count.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Call when a component becomes visible and wants polling.
    /// Starts the timer on the first subscriber; subsequent calls just increment the count.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            StartTimer();
        }
    }

    /// <summary>
    /// Call when a component is disposed or leaves the page.
    /// Stops the timer when the last subscriber leaves.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            StopTimer();
        }
    }

    private void StartTimer()
    {
        StopTimer();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopTimer()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fetch immediately on start, then every 10 seconds.
        await FetchAndNotifyAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (_timer is null || !await _timer.WaitForNextTickAsync(ct))
                    break;

                await FetchAndNotifyAsync();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        CurrentAlertCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertCountChanged?.Invoke();
    }

    /// <summary>
    /// When the warehouse changes, immediately re-fetch alerts so all
    /// subscribers see data for the new warehouse.
    /// </summary>
    private void OnWarehouseChanged()
    {
        if (_subscriberCount > 0)
        {
            // Restart the timer so the next 10-second window begins now.
            StartTimer();
        }
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= OnWarehouseChanged;
        StopTimer();
    }
}

