@inject WarehouseState Warehouse
@implements IDisposable
@rendermode InteractiveServer

<div class="d-flex align-items-center gap-2">
    <label class="form-label mb-0 text-nowrap" for="warehouse-select">
        <strong>Warehouse:</strong>
    </label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@Warehouse.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in WarehouseState.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            Warehouse.SetWarehouse(newId);
        }
    }

    // If another component ever changes the warehouse, keep this dropdown in sync.
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        Warehouse.OnChange += _handler;
    }

    public void Dispose() => Warehouse.OnChange -= _handler;
}

