@page "/dashboard"
@using sv_879ae826edc24b989e8f493005b62180.Services
@inject WarehouseState Warehouse
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Viewing: <strong>@Warehouse.CurrentWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(AlertService.CurrentAlertCount > 5 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(AlertService.CurrentAlertCount > 5 ? "text-danger" : "text-success")">
                    @AlertService.CurrentAlertCount
                </p>
                <p class="text-muted mb-0">items below minimum level</p>
            </div>
        </div>
    </div>

    <div class="col-md-8">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Alert Details</h5>
                @if (AlertService.CurrentAlertCount == 0)
                {
                    <div class="alert alert-success mb-0">
                        ✅ All inventory levels are healthy at <strong>@Warehouse.CurrentWarehouseName</strong>.
                    </div>
                }
                else if (AlertService.CurrentAlertCount <= 5)
                {
                    <div class="alert alert-warning mb-0">
                        ⚠️ <strong>@AlertService.CurrentAlertCount</strong> item(s) are running low at
                        <strong>@Warehouse.CurrentWarehouseName</strong>. Consider reordering soon.
                    </div>
                }
                else
                {
                    <div class="alert alert-danger mb-0">
                        🚨 <strong>@AlertService.CurrentAlertCount</strong> item(s) critically low at
                        <strong>@Warehouse.CurrentWarehouseName</strong>. Immediate action required!
                    </div>
                }
                <p class="text-muted mt-2 mb-0">
                    <small>Auto-refreshes every 10 seconds. Last checked: @_lastChecked.ToString("HH:mm:ss")</small>
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime _lastChecked = DateTime.Now;
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        Warehouse.OnChange += _warehouseHandler;

        _alertHandler = () => InvokeAsync(() =>
        {
            _lastChecked = DateTime.Now;
            StateHasChanged();
        });
        AlertService.OnAlertCountChanged += _alertHandler;

        // Start polling — the service tracks subscriber count and manages the timer.
        AlertService.StartPolling();
    }

    public void Dispose()
    {
        Warehouse.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;
        AlertService.StopPolling();
    }
}

